"""Search Stepper

This activity traces binary search by hand, one step at a time, all against ONE fixed, canonical implementation and ONE fixed 10-element sorted array, so every question is a concrete arithmetic trace rather than a new algorithm to learn. The canonical implementation used in every question: v is sorted ascending; lo starts at 0 and hi starts at n (a half-open range [lo, hi) -- lo is a valid candidate index, hi is one PAST the last candidate, matching the end() fence-post convention from iterator-walk); the loop runs while (lo < hi); mid is always computed as mid = lo + (hi - lo) / 2 (integer division, rounds down); if v[mid] is less than the target, lo becomes mid + 1, otherwise hi becomes mid; the loop stops when lo == hi, and lo is checked against the target afterward to know whether it was found. Every answer here is a specific number (or a pair of numbers) -- the exact format expected is stated in each question.
"""
import json, sys

# -- Crypto / obfuscation --
_KEY_A = "923398f499a6cacee61c993996a6c1406e93c240588261f46131b30a4a6aa9de"
_KEY_B = "2b901178c050cdd6db787a826f5eacf3a4ba8a9df14a2bce8189cfe4f25cb84f"
import base64 as _b64, hashlib as _hl, hmac as _hm, json as _js, zlib as _zl

_SALT      = bytes.fromhex("a3f1b2c4d5e6f7a8b9c0d1e2f3a4b5c6")
_KDF_ITERS = 100000

# Split runtime key. This is obfuscation only; do not treat it as a secret.
def _xor_bytes(a, b):
    return bytes(x ^ y for x, y in zip(a, b))

def _runtime_key():
    return _xor_bytes(bytes.fromhex(_KEY_A), bytes.fromhex(_KEY_B))

def _derive_key(answers):
    return _hl.pbkdf2_hmac("sha256", "|".join(answers).encode(), _SALT, _KDF_ITERS)

def _stream(key, length):
    ks, i = b"", 0
    while len(ks) < length:
        ks += _hl.sha256(key + i.to_bytes(4, "little")).digest()
        i += 1
    return ks[:length]

def _decrypt(blob_hex, answers):
    blob    = bytes.fromhex(blob_hex)
    key     = _derive_key(answers)
    ct, mac = blob[:-32], blob[-32:]
    if not _hm.compare_digest(mac, _hm.new(key, ct, _hl.sha256).digest()):
        return None
    return bytes(a ^ b for a, b in zip(ct, _stream(key, len(ct)))).decode()

def _item_key(label):
    return _hm.new(_runtime_key(), label.encode(), _hl.sha256).digest()

def _open_secret(blob_text, label):
    try:
        blob = _b64.b85decode(blob_text.encode())
        key = _item_key(label)
        ct, mac = blob[:-32], blob[-32:]
        if not _hm.compare_digest(mac, _hm.new(key, ct, _hl.sha256).digest()):
            return None
        pt = _xor_bytes(ct, _stream(key, len(ct)))
        data = _js.loads(_zl.decompress(pt).decode())
        return data if isinstance(data, dict) else None
    except Exception:
        return None

